 * treat the peer as a friend: identity, dial hint, both read-tickets, and the verified profile.
 */
public struct PairResult: Equatable, Hashable {
    public var sessionId: Data
    public var peerEndpointId: Data
    public var peerRecvPub: Data
    public var peerEndpointTicket: String
    public var peerProfileTicket: String
    public var peerTrailTicket: String
    public var peerProfile: ProfileView?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(sessionId: Data, peerEndpointId: Data, peerRecvPub: Data, peerEndpointTicket: String, peerProfileTicket: String, peerTrailTicket: String, peerProfile: ProfileView?) {
        self.sessionId = sessionId
        self.peerEndpointId = peerEndpointId
        self.peerRecvPub = peerRecvPub
        self.peerEndpointTicket = peerEndpointTicket
        self.peerProfileTicket = peerProfileTicket
        self.peerTrailTicket = peerTrailTicket
        self.peerProfile = peerProfile
    }

    

    
}

