public enum LocationError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case Crypto(String
    )
    case Network(String
    )
    case Decode(String
    )
    case NotStarted

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension LocationError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeLocationError: FfiConverterRustBuffer {
    typealias SwiftType = LocationError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> LocationError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Crypto(
            try FfiConverterString.read(from: &buf)
            )
        case 2: return .Network(
            try FfiConverterString.read(from: &buf)
            )
        case 3: return .Decode(
            try FfiConverterString.read(from: &buf)
            )
        case 4: return .NotStarted

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: LocationError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Crypto(v1):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .Network(v1):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .Decode(v1):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(v1, into: &buf)
            
        
        case .NotStarted:
            writeInt(&buf, Int32(4))
        
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeLocationError_lift(_ buf: RustBuffer) throws -> LocationError {
    return try FfiConverterTypeLocationError.lift(buf)
}

