// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * The kind of a polled pairing event.
 */

public enum PairEventKind: Equatable, Hashable {
    
    /**
     * A peer wants to pair (or our outbound Hello landed) — prompt the user.
     */
    case pendingRequest
    /**
     * The SAS visual gate is ready — fetch `pair_sas_challenge` and show it.
     */
    case verifying
    /**
     * The peer sent their accept/reject.
     */
    case peerResponded
    /**
     * Both sides accepted — call `pair_result`.
     */
    case ready
    /**
     * The session was rejected by either side.
     */
    case rejected
    /**
     * The session failed (SAS mismatch/cancel/timeout or a protocol error).
     */
    case failed





}

#if compiler(>=6)
extension PairEventKind: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypePairEventKind: FfiConverterRustBuffer {
    typealias SwiftType = PairEventKind

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> PairEventKind {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .pendingRequest
        
        case 2: return .verifying
        
        case 3: return .peerResponded
        
        case 4: return .ready
        
        case 5: return .rejected
        
        case 6: return .failed
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: PairEventKind, into buf: inout [UInt8]) {
        switch value {
        
        
        case .pendingRequest:
            writeInt(&buf, Int32(1))
        
        
        case .verifying:
            writeInt(&buf, Int32(2))
        
        
        case .peerResponded:
            writeInt(&buf, Int32(3))
        
        
        case .ready:
            writeInt(&buf, Int32(4))
        
        
        case .rejected:
            writeInt(&buf, Int32(5))
        
        
        case .failed:
            writeInt(&buf, Int32(6))
        
        }
    }
}


